import { useMutation, useQuery } from '@tanstack/react-query';
import { cloneDeep } from 'lodash-es';
import { useContext, useState } from 'react';

import { getCurrentUserDetails } from '@dynatrace-sdk/app-environment';
import {
  isForbidden,
  isNotFound,
  isUnauthorized,
  stateClient,
} from '@dynatrace-sdk/client-state';

import { useRecentAndPinnedFiltersStore } from './useRecentFiltersStore.js';
import { RecentAndSavedFiltersQueryClientContext } from '../../contexts/SavedAndRecentQueryClientContext.js';
import { type StoredFilter } from '../../state/recent-pinned-store.js';
import { useFilterFieldLoggerContext } from '../useFilterFieldLoggerContext.js';

const currentUser = getCurrentUserDetails();

/**
 * Helper function to read a persisted stored filter from the app state.
 * @internal
 */
export function usePersistedFilter(
  name: string | null,
  key: string,
  saveFn: (filters: Array<StoredFilter>) => void,
) {
  const queryClient = useContext(RecentAndSavedFiltersQueryClientContext);
  const setCanPin = useRecentAndPinnedFiltersStore(
    (state) => state.setCanPin,
    name,
  );
  const { logger } = useFilterFieldLoggerContext();

  return useQuery(
    {
      enabled: name !== null,
      queryKey: [key],
      throwOnError: false,
      queryFn: async ({ signal }) => {
        let savedFilters;

        try {
          savedFilters = await stateClient.getUserAppState({
            key: key,
            abortSignal: signal,
          });
        } catch (error) {
          if (isUnauthorized(error) || isForbidden(error)) {
            logger?.warn(
              'FilterField pinned and recent error - permissions not met',
              error,
            );
            setCanPin(false);
          } else if (signal.aborted) {
            // Query was intentionally cancelled (e.g. by a concurrent mutation) — not an error.
          } else if (!isNotFound(error)) {
            // Some other error.
            logger?.warn('FilterField pinned and recent error', error);
          }

          return [];
        }

        const parsedValue = JSON.parse(savedFilters.value, (key, value) => {
          if (key === 'timeUsed') {
            return new Date(value);
          }
          return value;
        });

        // Migration if a stored filter does not have a time saved
        for (const parsedFilter of parsedValue) {
          if (!parsedFilter.timeUsed) {
            parsedFilter.timeUsed = new Date();
          }
        }

        saveFn(parsedValue);
        return parsedValue;
      },
    },
    queryClient,
  );
}

/**
 * Helper function to mutate the persisted stored filters in the app state.
 * Depending on the actionType, it can pin, unpin or save filter.
 * @internal
 */
export function usePersistedFilterMutation(
  key: string,
  name: string | null,
  actionType: 'pin' | 'unpin' | 'save',
) {
  const queryClient = useContext(RecentAndSavedFiltersQueryClientContext);
  const { logger } = useFilterFieldLoggerContext();
  const setCanPin = useRecentAndPinnedFiltersStore(
    (state) => state.setCanPin,
    name,
  );

  const state = useRecentAndPinnedFiltersStore((state) => {
    if (actionType === 'save') {
      return state.recentFilters;
    }

    return state.pinnedFilters;
  }, name);

  const setState = useRecentAndPinnedFiltersStore((state) => {
    if (actionType === 'save') {
      return state.setRecentFilters;
    }

    return state.setPinnedFilters;
  }, name);

  const action = useRecentAndPinnedFiltersStore((state) => {
    if (actionType === 'save') {
      return state.saveRecentFilter;
    }

    if (actionType === 'pin') {
      return state.pinFilter;
    }

    return state.unpinFilter;
  }, name);

  const [previousState, setPreviousState] = useState<StoredFilter[]>(
    cloneDeep(state),
  );

  return useMutation(
    {
      mutationKey: [key],
      throwOnError: false,
      mutationFn: async (filterString: string) => {
        // Early exit for opt out
        if (name === null) {
          return Promise.resolve();
        }

        // Make sure we actually store values into the system.
        if (filterString.trim() === '') {
          return Promise.resolve();
        }

        setPreviousState(cloneDeep(state));
        const newState = action(filterString);

        await queryClient.cancelQueries({
          queryKey: [key],
        });

        try {
          await stateClient.setUserAppState({
            body: {
              validUntilTime: null,
              modificationInfo: {
                lastModifiedBy: currentUser.id,
                lastModifiedTime: new Date(),
              },
              value: JSON.stringify(newState),
            },
            key,
          });

          return newState;
        } catch (error) {
          if (isUnauthorized(error) || isForbidden(error)) {
            logger?.warn(
              'FilterField pinned and recent error - permissions not met',
              error,
            );
            setCanPin(false);
          } else {
            // Some other error.
            logger?.warn('FilterField pinned and recent error', error);
          }
          setState(previousState);
        }
        return state;
      },
      onError: (error) => {
        setState(previousState);
        // Keep the TanStack cache consistent with the Zustand rollback.
        queryClient.setQueryData([key], previousState);
        if (isUnauthorized(error) || isForbidden(error)) {
          logger?.warn(
            'FilterField pinned and recent error - permissions not met',
            error,
          );
          setCanPin(false);
        }
      },
      onSuccess: (newState) => {
        // We already know what we PUT — write it straight into the cache
        // so no follow-up GET is needed.
        if (newState !== undefined) {
          queryClient.setQueryData([key], newState);
        }
      },
    },
    queryClient,
  );
}
